// Usage in M5GFX:
// canvas->pushImageDMA(x, y, EVA_LOGO_W, EVA_LOGO_H,
//   (uint16_t*)EVA_LOGO);
// Center on 240px wide display: x = (240 - EVA_LOGO_W) / 2 = 10
// ============================================================
// drawEvaLogo() — disegna il logo centrato a y specificata
// Chiamata tipica in SplashScene::render():
//   drawEvaLogo(R.canvas(), 35);
// ============================================================
inline void drawEvaLogo(LGFX_Sprite* canvas, int16_t y) {
    constexpr int16_t x = (240 - EVA_LOGO_W) / 2;  // = 10
    canvas->pushImageDMA(x, y, EVA_LOGO_W, EVA_LOGO_H,
                         (uint16_t*)EVA_LOGO);
}
